usage.basic:
const pane = new ZASidePane();
pane.show({
  header1: 'Panel Title',
  body1: contentElement,
  footer1: pane.constructFooterEl({ buttonList: [{ name: 'Save', isPrimary: true }, { name: 'Cancel' }] })
});

usage.withDesc:
pane.show({
  header1: 'Title',
  desc1: 'Subtitle or description',
  body1: contentElement
});

